353: Tracing::Reason ConnectionManagerUtility::mutateTracingRequestHeader(
354:     RequestHeaderMap& request_headers, Runtime::Loader& runtime, ConnectionManagerConfig& config,
355:     const Router::Route* route) {
356:   Tracing::Reason final_reason = Tracing::Reason::NotTraceable;
357:   if (!config.tracingConfig()) {
358:     return final_reason;
359:   }
360: 
361:   auto rid_extension = config.requestIDExtension();
362:   if (!rid_extension->useRequestIdForTraceSampling()) {
363:     return Tracing::Reason::Sampling;
364:   }
365:   const auto rid_to_integer = rid_extension->getInteger(request_headers);
366:   // Skip if request-id is corrupted, or non-existent
367:   if (!rid_to_integer.has_value()) {
368:     return final_reason;
369:   }
370:   const uint64_t result = rid_to_integer.value() % 10000;
371: 
372:   const envoy::type::v3::FractionalPercent* client_sampling =
373:       &config.tracingConfig()->client_sampling_;
374:   const envoy::type::v3::FractionalPercent* random_sampling =
375:       &config.tracingConfig()->random_sampling_;
376:   const envoy::type::v3::FractionalPercent* overall_sampling =
377:       &config.tracingConfig()->overall_sampling_;
378: 
379:   if (route && route->tracingConfig()) {
380:     client_sampling = &route->tracingConfig()->getClientSampling();
381:     random_sampling = &route->tracingConfig()->getRandomSampling();
382:     overall_sampling = &route->tracingConfig()->getOverallSampling();
383:   }
384: 
385:   // Do not apply tracing transformations if we are currently tracing.
386:   final_reason = rid_extension->getTraceReason(request_headers);
387:   if (Tracing::Reason::NotTraceable == final_reason) {
388:     if (request_headers.ClientTraceId() &&
389:         runtime.snapshot().featureEnabled("tracing.client_enabled", *client_sampling)) {
390:       final_reason = Tracing::Reason::ClientForced;
391:       rid_extension->setTraceReason(request_headers, final_reason);
392:     } else if (request_headers.EnvoyForceTrace()) {
393:       final_reason = Tracing::Reason::ServiceForced;
394:       rid_extension->setTraceReason(request_headers, final_reason);
395:     } else if (runtime.snapshot().featureEnabled("tracing.random_sampling", *random_sampling,
396:                                                  result)) {
397:       final_reason = Tracing::Reason::Sampling;
398:       rid_extension->setTraceReason(request_headers, final_reason);
399:     }
400:   }
